import React, { useState, useRef, useEffect } from 'react';
import './AIAssistant.css';
import { useAuth } from '../context/AuthContext';
import { getApplications, getCourses, getReviews } from '../services/api';

const API_KEY = process.env.REACT_APP_GEMINI_API_KEY;
const SYSTEM_CONTEXT = `You are EduAdmit AI, a helpful college admissions assistant for a college admission portal.
You help students with:
- Course selection advice (B.Tech IT, B.Tech CSE, BBA and other programs)
- Admission process guidance (registration, application, documents, payment)
- Document requirements (marksheets, ID proof, etc.)
- Application status understanding
- Career advice related to courses
- General college admission tips

Keep responses concise, friendly and helpful. Use bullet points for lists.
If asked about specific personal information (passwords, etc.) politely decline.
Always encourage students to use the platform to apply.`;

const SUGGESTIONS = [
  'Which course is best for a software career?',
  'What documents do I need to apply?',
  'How long does admission take?',
  'What is the application fee?',
  'Tell me about B.Tech CSE',
  'How to check my application status?',
];

const getLocalFallbackReply = (userMsg) => {
  const demoResponses = {
    course: '**B.Tech CSE** is ideal for software engineering careers, while **B.Tech IT** focuses on practical systems and networking. **BBA** is better for management and business careers.',
    document: 'For admission, you typically need:\n- 10th and 12th marksheets\n- Government ID\n- Passport-size photos\n- Transfer certificate (if applicable)\n- Character certificate',
    fee: 'The application fee is usually **Rs.500**, payable via UPI, card, or net banking.',
    status: 'You can track your application in **Dashboard -> My Status**.',
    default: 'I can still help with admission guidance. Ask me about courses, documents, fees, or status.'
  };

  const key = Object.keys(demoResponses).find((k) => userMsg.toLowerCase().includes(k));
  return demoResponses[key] || demoResponses.default;
};

function AIAssistant() {
  const { student } = useAuth();
  const [messages, setMessages] = useState([
    {
      role: 'assistant',
      content: "Hello! I am EduAdmit AI. I can help with courses, documents, fees, and application status.",
      time: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [dbSnapshot, setDbSnapshot] = useState({ courses: [], myApps: [], myReviews: [] });
  const [reviewsUnavailable, setReviewsUnavailable] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  useEffect(() => {
    let active = true;

    const loadDbSnapshot = async () => {
      const results = await Promise.allSettled([getCourses(), getApplications(), getReviews()]);
      if (!active) return;

      const courses = results[0].status === 'fulfilled' && Array.isArray(results[0].value.data)
        ? results[0].value.data
        : [];
      const allApps = results[1].status === 'fulfilled' && Array.isArray(results[1].value.data)
        ? results[1].value.data
        : [];
      const allReviews = results[2].status === 'fulfilled' && Array.isArray(results[2].value.data)
        ? results[2].value.data
        : [];

      const myApps = student
        ? allApps.filter((a) => a.student?.stId === student.stId || a.stId === student.stId)
        : [];
      const myAppIds = new Set(myApps.map((a) => a.appId));
      const myReviews = allReviews.filter((r) => myAppIds.has(r.appId || r.application?.appId));

      setDbSnapshot({ courses, myApps, myReviews });
      setReviewsUnavailable(results[2].status !== 'fulfilled');
    };

    loadDbSnapshot();
    return () => { active = false; };
  }, [student]);

  const getDbBasedReply = (userMsg) => {
    const text = userMsg.toLowerCase();

    if (text.includes('course') || text.includes('program')) {
      if (dbSnapshot.courses.length === 0) return null;
      const courseList = dbSnapshot.courses.map((c) => `- ${c.courseName} (${c.dept}, ${c.duration})`).join('\n');
      return `Here are the courses currently available in the system:\n${courseList}`;
    }

    const asksStatus = text.includes('status') || text.includes('application') || text.includes('my app');
    if (asksStatus) {
      if (!student) return 'Please log in first so I can show your application status from the database.';
      if (dbSnapshot.myApps.length === 0) return 'I checked the database and you currently have no applications.';

      const statusList = dbSnapshot.myApps
        .map((a) => `- Application #${a.appId}: ${a.status}`)
        .join('\n');

      if (reviewsUnavailable) {
        return `From the database, your applications are:\n${statusList}\n\nNote: review remarks are temporarily unavailable because the reviews API is returning an internal server error.`;
      }

      return `From the database, your applications are:\n${statusList}`;
    }

    return null;
  };

  const buildDbContext = () => {
    const courseNames = dbSnapshot.courses.map((c) => c.courseName).join(', ') || 'No courses available';
    const appSummary = dbSnapshot.myApps.length
      ? dbSnapshot.myApps.map((a) => `#${a.appId}:${a.status}`).join(', ')
      : 'No applications for current student';

    return `Portal DB context:\nCourses: ${courseNames}\nMy applications: ${appSummary}\nReviews API healthy: ${reviewsUnavailable ? 'No' : 'Yes'}`;
  };

  const sendMessage = async (text) => {
    const userMsg = text || input.trim();
    if (!userMsg) return;

    setInput('');
    setMessages((prev) => [...prev, { role: 'user', content: userMsg, time: new Date() }]);
    setLoading(true);

    try {
      const dbReply = getDbBasedReply(userMsg);
      if (dbReply) {
        await new Promise((r) => setTimeout(r, 300));
        setMessages((prev) => [...prev, { role: 'assistant', content: dbReply, time: new Date() }]);
        return;
      }

      if (!API_KEY || API_KEY === 'your_gemini_api_key_here') {
        setMessages((prev) => [...prev, { role: 'assistant', content: getLocalFallbackReply(userMsg), time: new Date() }]);
        return;
      }

      const history = messages.slice(-10).map((m) => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));

      const response = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${API_KEY}`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            contents: [
              { role: 'user', parts: [{ text: `${SYSTEM_CONTEXT}\n\n${buildDbContext()}` }] },
              { role: 'model', parts: [{ text: 'Understood! I am EduAdmit AI, ready to help.' }] },
              ...history,
              { role: 'user', parts: [{ text: userMsg }] }
            ],
            generationConfig: { maxOutputTokens: 500, temperature: 0.7 }
          })
        }
      );

      const data = await response.json();

      if (!response.ok) {
        const reason = data?.error?.message || `Gemini request failed (${response.status})`;
        setMessages((prev) => [...prev, {
          role: 'assistant',
          content: `I couldn't get a Gemini response: ${reason}.\n\nLocal answer:\n${getLocalFallbackReply(userMsg)}`,
          time: new Date()
        }]);
        return;
      }

      const blockReason = data?.promptFeedback?.blockReason;
      if (blockReason) {
        setMessages((prev) => [...prev, {
          role: 'assistant',
          content: `Gemini blocked this request (${blockReason}). Please rephrase your question.`,
          time: new Date()
        }]);
        return;
      }

      const reply = data?.candidates?.[0]?.content?.parts?.[0]?.text;
      if (!reply) {
        setMessages((prev) => [...prev, {
          role: 'assistant',
          content: `Gemini returned an empty response.\n\nLocal answer:\n${getLocalFallbackReply(userMsg)}`,
          time: new Date()
        }]);
        return;
      }

      setMessages((prev) => [...prev, { role: 'assistant', content: reply, time: new Date() }]);
    } catch {
      setMessages((prev) => [...prev, {
        role: 'assistant',
        content: `I am having trouble connecting right now.\n\nLocal answer:\n${getLocalFallbackReply(userMsg)}`,
        time: new Date()
      }]);
    } finally {
      setLoading(false);
    }
  };

  const formatMessage = (content) => {
    return content
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/\n/g, '<br/>');
  };

  const formatTime = (date) => date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

  return (
    <div className="ai-page page-wrapper">
      <div className="ai-layout">
        <div className="ai-sidebar">
          <div className="ais-header">
            <div className="ais-logo">AI</div>
            <h3>EduAdmit AI</h3>
            <p>Powered by Google Gemini</p>
          </div>
          <div className="ais-suggestions">
            <div className="ais-section-title">Quick Questions</div>
            {SUGGESTIONS.map((s, i) => (
              <button key={i} className="ais-suggestion" onClick={() => sendMessage(s)}>
                {s}
              </button>
            ))}
          </div>
        </div>

        <div className="ai-chat-area">
          <div className="aca-header">
            <div className="aca-bot">
              <div className="aca-bot-icon">AI</div>
              <div>
                <div className="aca-bot-name">EduAdmit AI Assistant</div>
                <div className="aca-bot-status">Online - Ready to help</div>
              </div>
            </div>
            <button className="aca-clear" onClick={() => setMessages([messages[0]])}>Clear Chat</button>
          </div>

          <div className="aca-messages">
            {messages.map((msg, i) => (
              <div key={i} className={`message ${msg.role}`}>
                {msg.role === 'assistant' && <div className="msg-avatar">AI</div>}
                <div className="msg-content">
                  <div className="msg-bubble" dangerouslySetInnerHTML={{ __html: formatMessage(msg.content) }} />
                  <div className="msg-time">{formatTime(msg.time)}</div>
                </div>
                {msg.role === 'user' && <div className="msg-user-avatar">You</div>}
              </div>
            ))}
            {loading && (
              <div className="message assistant">
                <div className="msg-avatar">AI</div>
                <div className="msg-content">
                  <div className="msg-bubble typing">
                    <div className="typing-dots">
                      <span></span><span></span><span></span>
                    </div>
                  </div>
                </div>
              </div>
            )}
            <div ref={bottomRef} />
          </div>

          <div className="aca-input-area">
            <div className="aca-input-row">
              <input
                type="text"
                className="aca-input"
                placeholder="Ask me anything about college admissions..."
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && !loading && sendMessage()}
                disabled={loading}
              />
              <button className="aca-send" onClick={() => sendMessage()} disabled={loading || !input.trim()}>
                {loading ? '...' : 'Send'}
              </button>
            </div>
            <p className="aca-disclaimer">
              AI responses are for guidance only. For official information, contact admissions office.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AIAssistant;
